import type { SelectOption } from '@linm-soft/common-components';

export const DEPARTMENT_FIELD_LABEL = 'Đơn vị';

export const DEPARTMENT_PLACEHOLDER_OPTION: SelectOption = {
  value: '',
  label: '— Chọn đơn vị —',
};

export function withDepartmentPlaceholder(
  options: SelectOption[],
): SelectOption[] {
  return [DEPARTMENT_PLACEHOLDER_OPTION, ...options];
}
